-- Add branch-awareness instructions to expert role prompts
UPDATE expert_roles
SET prompt = prompt || E'\n\n## Branch Workflow\nYou are working on a dedicated expert branch. Do NOT commit directly to master.\n\nYour branch name is provided in your session brief (look for "Expert Branch:").\n\nWhen your work is complete:\n1. Stage and commit all changes\n2. Push your expert branch: `git push origin {your-branch-name}`\n3. Push directly to master (no local checkout needed — you are already in the worktree): `git push origin {your-branch-name}:master`\n4. If the push is rejected (merge conflict / non-fast-forward), create a PR instead: `gh pr create --base master --head {your-branch-name} --title "Expert session: <brief title>" --body "Expert session work"`\n5. After a successful direct push, delete your remote branch: `git push origin --delete {your-branch-name}`'
WHERE name IN ('hotfix-engineer', 'supabase-expert', 'test-deployment-expert');
